`define CHECK(signal, expected, msg) \
  if ((signal) !== (expected)) begin \
    $display("FAIL: %s  got=%0d  exp=%0d", msg, signal, expected); \
    fail_count = fail_count + 1; \
  end else begin \
    $display("PASS: %s", msg); \
    pass_count = pass_count + 1; \
  end

integer pass_count = 0;
integer fail_count = 0;

// ─── Vector 00: PG-LF → SG-HF ───
task run_vector_00;
begin
  $display("--- Vector 00: true=PG-LF ---");
  // Feed ADC samples (round-robin ch 0..7, 250 rounds)
  for (int round = 0; round < 250; round++) begin
    for (int ch = 0; ch < 8; ch++) begin
      @(posedge clk);
      adc_valid   = 1;
      adc_channel = ch;
      adc_sample  = adc_mem_00[ch][round];
    end
    @(posedge clk); adc_valid = 0;
  end

  // Wait for window_ready
  @(posedge window_ready);
  @(posedge clk);

  // Check SBP features (after sbp_done)
  @(posedge sbp_done);
  @(posedge clk);
  `CHECK(sbp_features[0], 8'h27, "vec00 sbp[0]=39");
  `CHECK(sbp_features[1], 8'h1A, "vec00 sbp[1]=26");
  `CHECK(sbp_features[2], 8'h2C, "vec00 sbp[2]=44");
  `CHECK(sbp_features[3], 8'h26, "vec00 sbp[3]=38");
  `CHECK(sbp_features[4], 8'h22, "vec00 sbp[4]=34");
  `CHECK(sbp_features[5], 8'h21, "vec00 sbp[5]=33");
  `CHECK(sbp_features[6], 8'h22, "vec00 sbp[6]=34");
  `CHECK(sbp_features[7], 8'h1F, "vec00 sbp[7]=31");

  // Check MLP class scores (after mlp_done)
  @(posedge mlp_done);
  @(posedge clk);
  `CHECK(class_scores[0], 32'h000185B3, "vec00 score[0]=99763");
  `CHECK(class_scores[1], 32'hFFFAC19A, "vec00 score[1]=-343654");
  `CHECK(class_scores[2], 32'hFFFA698B, "vec00 score[2]=-366197");
  `CHECK(class_scores[3], 32'h0001CA0A, "vec00 score[3]=117258");

  // Check final prediction
  `CHECK(predicted_class, 2'b11, "vec00 class=3 (SG-HF)");
